<template>
  <div class="inspection-list">
    <!-- 顶部筛选标签：使用 TDesign Tabs -->
    <!-- 关键：使用 v-model 双向绑定当前标签页 -->
    <t-tabs v-model="activeTab" placement="top">
      <t-tab-panel value="all" label="全部" />
      <t-tab-panel value="detected" label="已检测" />
      <t-tab-panel value="undetected" label="未检测" />
    </t-tabs>

    <div v-if="activeTab==='detected'" class="detected-filter">
      <t-select v-model="detectedFilter" style="width: 160px" placeholder="选择类型">
        <t-option value="all" label="全部" />
        <t-option value="qualified" label="合格" />
        <t-option value="exception" label="异常" />
      </t-select>
    </div>

    <!-- 后端异常提示：使用 TDesign Alert -->
    <t-alert
      v-if="hasBackendError"
      theme="error"
      title="后端异常"
      :description="backendError || '请检查后端服务是否正常运行'"
      close
    >
      <template #operation>
        <t-button size="small" variant="base" @click="retryConnection">重试连接</t-button>
      </template>
    </t-alert>

    <!-- 列表容器与空态：后端正常时展示。根据筛选结果有无数据切换显示 -->
    <template v-else>
      <!-- 有数据：展示列表 -->
      <t-list v-if="filteredRecords.length > 0" class="list-container" split>
        <t-list-item
          v-for="record in filteredRecords"
          :key="record.id"
          @click="selectRecord(record)"
          :class="{ active: currentRecord && currentRecord.id === record.id }"
        >
          <div class="item-row">
            <!-- 选择框：使用 TDesign Checkbox -->
            <!-- 阻止点击冒泡，防止触发 list-item 的点击事件导致双重切换 -->
            <div @click.stop v-if="isBatchMode">
              <t-checkbox
                :checked="isRecordSelected(record.id)"
                @change="toggleRecord(record.id)"
              />
            </div>
            <div class="record-info">
              <!-- 场景名：仅展示场景名，不再展示ID -->
              <div class="record-scene">{{ getSceneName(record) }}</div>
              <!-- 检测日期：显示在检测时间上方 -->
              <div class="record-date">检测日期：{{ safeDateText(record) }}</div>
              <!-- 检测时间：保持原有格式化逻辑 -->
              <div class="record-time">检测时间：{{ record.time || formatTime(record.timestamp) }}</div>
              <!-- 状态标签：在“已检测”页显示 合格/异常；其它页保持语义合理展示 -->
              <t-tag :theme="statusTheme(record)" variant="light" size="small">
                {{ statusText(record) }}
              </t-tag>
            </div>
          </div>
        </t-list-item>
      </t-list>
      <!-- 无数据：在列表区域居中显示空态 -->
      <div v-else class="list-empty">
        <!-- 使用 TDesign Empty 组件，容器通过 flex 居中 -->
        <t-empty description="暂无数据" />
      </div>
    </template>

    <!-- 将选择按钮放在底部导出按钮的上方，视觉更贴近列表操作区域 -->
    <div class="list-toolbar" v-if="isBatchMode">
      <t-space>
        <t-button theme="primary" @click="selectAllFiltered">全选</t-button>
        <t-button theme="default" variant="outline" @click="clearSelectionFiltered">取消选择</t-button>
      </t-space>
    </div>

    <!-- 底部操作按钮：使用 TDesign Button -->
    <div class="action-buttons" v-if="false">
      <t-button block type="primary" :disabled="filteredRecords.length === 0 || hasBackendError">导出报告</t-button>
    </div>
  </div>
</template>

<script>
import { mapState, mapActions } from 'vuex';

export default {
  name: 'InspectionList',
  data() {
    return {
      activeTab: 'all',
      detectedFilter: 'all'
    };
  },
  computed: {
    // 引入场景名称映射，用于根据 sceneId 显示场景中文名
    ...mapState(['inspectionRecords', 'currentRecord', 'backendStatus', 'backendError', 'sceneNameMap', 'isBatchMode', 'batchSelectedIds']),
    hasBackendError() {
      return this.backendStatus === 'error';
    },
    filteredRecords() {
      const records = this.inspectionRecords || [];
      const tab = this.activeTab;
      if (tab === 'all') return records;
      if (tab === 'undetected') return records.filter(r => r && r.isDetected === false);
      if (tab === 'detected') {
        if (this.detectedFilter === 'qualified') return records.filter(r => r && r.isDetected === true && r.hasIssue !== true);
        if (this.detectedFilter === 'exception') return records.filter(r => r && r.isDetected === true && r.hasIssue === true);
        return records.filter(r => r && r.isDetected === true);
      }
      return records;
    }
  },
  methods: {
    ...mapActions(['setCurrentRecord', 'fetchImagesFromServer', 'fetchSceneNameMap', 'fetchImagesByFilter']),
    // 选中记录
    selectRecord(record) {
      if (this.isBatchMode) {
        // 批量模式下点击整个条目也可以触发选择切换
        this.toggleRecord(record.id);
        return;
      }
      this.setCurrentRecord(record);
    },
    // 判断记录是否在批量选择中
    isRecordSelected(id) {
      if (!this.batchSelectedIds) return false;
      return this.batchSelectedIds.includes(id);
    },
    // 切换记录选中状态
    toggleRecord(id) {
      this.$store.commit('TOGGLE_BATCH_SELECTED_ID', id);
    },
    // 全选当前筛选后的列表（适配新逻辑）
    selectAllFiltered() {
      const ids = this.filteredRecords.map(r => r.id);
      this.$store.commit('SET_BATCH_SELECTED_IDS', ids);
    },
    // 取消选择（适配新逻辑）
    clearSelectionFiltered() {
      this.$store.commit('SET_BATCH_SELECTED_IDS', []);
    },
    async retryConnection() {
      // 重试时按当前标签重新加载，避免仅请求全部列表
      await this.loadByTab();
    },
    getStatusText() {},
    statusTheme() {},
    statusText(record) {
      const det = record && record.isDetected === true;
      const issue = record && record.hasIssue === true;
      if (this.activeTab === 'detected') return issue ? '异常' : '合格';
      if (this.activeTab === 'undetected') return '未检测';
      return det ? (issue ? '异常' : '合格') : '未检测';
    },
    statusTheme(record) {
      const det = record && record.isDetected === true;
      const issue = record && record.hasIssue === true;
      if (this.activeTab === 'undetected') return 'warning';
      if (det) return issue ? 'danger' : 'success';
      return 'default';
    },
    // 仅展示场景名：根据 sceneId 查映射，若无映射则使用 record.sceneName/scene，最后回退“未知场景”
    getSceneName(record) {
      if (!record) return '未知场景';
      const id = record.sceneId != null ? String(record.sceneId) : null;
      const byMap = id && this.sceneNameMap ? this.sceneNameMap[id] : null;
      return byMap || record.sceneName || record.scene || '未知场景';
    },
    // 检测日期显示：优先使用 record.date；其次从 timestamp 格式化；都没有则显示“未知日期”
    safeDateText(record) {
      if (record && record.date) return record.date;
      if (record && record.timestamp) return this.formatDate(record.timestamp);
      return '未知日期';
    },
    formatDate(timestamp) {
      if (!timestamp) return '';
      const date = new Date(timestamp);
      return `${date.getFullYear()}/${(date.getMonth() + 1).toString().padStart(2, '0')}/${date.getDate().toString().padStart(2, '0')}`;
    },
    formatTime(timestamp) {
      if (!timestamp) return '';
      const date = new Date(timestamp);
      return `${date.getHours().toString().padStart(2, '0')}:${date.getMinutes().toString().padStart(2, '0')}`;
    },
    // 根据当前标签页加载数据：
    // - 全部：沿用旧接口获取所有图片
    // - 其余状态：改用 /images/filter 接口按状态获取
    async loadByTab() {
      if (this.activeTab === 'all') {
        await this.fetchImagesFromServer();
        return;
      }
      if (this.activeTab === 'undetected') {
        await this.fetchImagesByFilter({ status: 'undetected' });
        return;
      }
      if (this.activeTab === 'detected') {
        await this.fetchImagesFromServer();
        return;
      }
    }
  },
  async mounted() {
    // 首次进入：根据当前标签加载数据
    await this.loadByTab();
    try { await this.$store.dispatch('setListActiveTab', this.activeTab); } catch (_) {}
    // 并行获取场景名称映射（若后端支持），用于将 sceneId 显示为中文名称
    try {
      await this.fetchSceneNameMap();
    } catch (e) {
      // 后端未提供映射或请求失败时忽略，保持“未知场景”回退
      console.warn('场景名称映射获取失败，已使用回退显示:', e);
    }
    
    // 如果有记录但没有选中的记录，默认选中第一个
    if (this.inspectionRecords.length > 0 && !this.currentRecord) {
      this.selectRecord(this.inspectionRecords[0]);
    }
  },
  watch: {
    // 监听标签切换：每次切换都重新请求并刷新列表
    activeTab: {
      immediate: false,
      async handler() {
        await this.loadByTab();
        try { await this.$store.dispatch('setListActiveTab', this.activeTab); } catch (_) {}
        // 切换标签后，如有数据默认选中第一条（优先选当前过滤后的第一条）
        const first = (this.filteredRecords && this.filteredRecords[0]) || (this.inspectionRecords && this.inspectionRecords[0]) || null;
        if (first) {
          this.selectRecord(first);
        }
      }
    }
    ,
    detectedFilter: {
      immediate: false,
      async handler() {
        if (this.activeTab === 'detected') {
          // 仅前端过滤，无需额外请求
          const first = (this.filteredRecords && this.filteredRecords[0]) || (this.inspectionRecords && this.inspectionRecords[0]) || null;
          if (first) this.selectRecord(first);
        }
      }
    }
  }
}
</script>

<style scoped>
.inspection-list {
  display: flex;
  flex-direction: column;
  height: 100%;
  border-right: 1px solid var(--td-component-stroke);
  background-color: var(--td-bg-color-container);
}

.list-container {
  flex: 1;
  overflow-y: auto;
  padding: 0;
}

/* 空态容器 */
.list-empty {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 16px;
  color: var(--td-text-color-placeholder);
}

.active {
  background-color: var(--td-brand-color-light) !important;
  /* 左侧高亮条，TDesign 风格通常在左侧 */
  position: relative;
}

.active::before {
  content: '';
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 3px;
  background-color: var(--td-brand-color);
}

/* 列表项样式优化 */
:deep(.t-list-item) {
  padding: 12px 16px;
  cursor: pointer;
  transition: all 0.2s;
  border-bottom: 1px solid var(--td-component-stroke);
  background-color: var(--td-bg-color-container);
}

:deep(.t-list-item:hover) {
  background-color: var(--td-bg-color-secondarycontainer);
}

.item-row {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  width: 100%;
}

.record-info {
  flex: 1;
  min-width: 0;
}

/* 场景名 */
.record-scene {
  font-weight: 500;
  font-size: 14px;
  color: var(--td-text-color-primary);
  margin-bottom: 4px;
}

/* 检测日期 */
.record-date {
  font-size: 12px;
  color: var(--td-text-color-placeholder);
  margin-bottom: 2px;
  display: flex;
  align-items: center;
}

.record-time {
  font-size: 12px;
  color: var(--td-text-color-placeholder);
  margin-bottom: 8px;
}

.list-toolbar {
  padding: 12px 16px;
  display: flex;
  justify-content: center;
  border-top: 1px solid var(--td-component-stroke);
  background-color: var(--td-bg-color-container);
}

.detected-filter {
  padding: 12px 16px;
  background-color: var(--td-bg-color-container);
  border-bottom: 1px solid var(--td-component-stroke);
}

.action-buttons {
  padding: 16px;
  background-color: var(--td-bg-color-container);
  border-top: 1px solid var(--td-component-stroke);
}
</style>